arguments.argument:
if bMenuDisplayed=1
{
  if oKeyCodes.kCodePressed[3]=1
  {
    playSound(global.snd_MenuCursor,0,1,1)
    if curPos=1
    {
      curPos=curMax
      curY+=curInc*(curMax-1)
    }
    else
    {
      curPos-=1
      curY-=curInc
    }
  }
  else if oKeyCodes.kCodePressed[4]=1
  {
    playSound(global.snd_MenuCursor,0,1,1)
    if curPos=curMax
    {
      curPos=1
      curY-=curInc*(curMax-1)
    }
    else
    {
      curPos+=1
      curY+=curInc
    }
  }
  
  if oKeyCodes.kCodePressed[5]=1
  {
    if curPos=1 //Quit
    {
      bMenuDisplayed=0
      depth=50
      global.gamePaused=false
    }
    else if curPos=2 //First Offense
    {
      global.newMapX=192
      global.newMapY=560
      writeToPlayerGlobals()
      global.bTowerDefense=1
      room_goto(rTD_Lv1)
    }
    else if curPos=3 //Second Offense
    {
      global.newMapX=240
      global.newMapY=576
      writeToPlayerGlobals()
      global.bTowerDefense=2
      room_goto(rTD_Lv2)
    }
    else if curPos=4 //Optional 1
    {
      global.newMapX=256
      global.newMapY=576
      writeToPlayerGlobals()
      global.bTowerDefense=3
      room_goto(rTD_Lv3)
    }
    else if curPos=5 //Optional 2
    {
      global.newMapX=416
      global.newMapY=624
      writeToPlayerGlobals()
      global.bTowerDefense=4
      room_goto(rTD_Lv4)
    }
    else if curPos=6 //Optional 3
    {
      global.newMapX=272
      global.newMapY=576
      writeToPlayerGlobals()
      global.bTowerDefense=5
      room_goto(rTD_Lv5)
    }
  }
  else if oKeyCodes.kCodePressed[6]=1 //Cancel
  {
    curPos=1; curY=24
    bMenuDisplayed=0
    depth=50
    global.gamePaused=false
  }
}
